## Common patterns

### Resetting to page 1 on filter changes

When filters or search criteria change, reset pagination to the first page:

```tsx
const ProductList = () => {
  const [currentPage, setCurrentPage] = useState(1);
  const [searchQuery, setSearchQuery] = useState('');
  const [filteredItems, setFilteredItems] = useState([]);

  // Reset to page 1 when search changes
  useEffect(() => {
    setCurrentPage(1);
  }, [searchQuery]);

  return (
    <>
      <TextInput
        value={searchQuery}
        onChange={(e) => setSearchQuery(e.target.value)}
        placeholder="Search..."
      />

      <Pagination
        totalItems={filteredItems.length}
        currentPage={currentPage}
        onPageChange={setCurrentPage}
      />
    </>
  );
};
```

### Persisting pagination state

Store pagination state in URL query parameters for shareable links:

```tsx
const ProductList = () => {
  const [searchParams, setSearchParams] = useSearchParams();

  const currentPage = parseInt(searchParams.get('page') || '1', 10);
  const pageSize = parseInt(searchParams.get('size') || '20', 10);

  const handlePageChange = (page: number) => {
    setSearchParams({ page: page.toString(), size: pageSize.toString() });
  };

  const handlePageSizeChange = (size: number) => {
    setSearchParams({ page: '1', size: size.toString() });
  };

  return (
    <Pagination
      totalItems={500}
      currentPage={currentPage}
      pageSize={pageSize}
      onPageChange={handlePageChange}
      onPageSizeChange={handlePageSizeChange}
      enablePageSizeSelector
    />
  );
};
```

## Testing your implementation

These examples demonstrate how to test your implementation when using Pagination within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the pagination component renders with expected controls and labels

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Pagination, NimbusProvider } from "@commercetools/nimbus";

describe("Pagination - Basic rendering", () => {
  it("renders pagination navigation with accessible controls", () => {
    render(
      <NimbusProvider>
        <Pagination totalItems={100} />
      </NimbusProvider>
    );

    // Verify navigation element exists
    const nav = screen.getByRole("navigation", { name: /pagination/i });
    expect(nav).toBeInTheDocument();

    // Verify previous/next buttons
    expect(
      screen.getByRole("button", { name: /go to previous page/i })
    ).toBeInTheDocument();
    expect(
      screen.getByRole("button", { name: /go to next page/i })
    ).toBeInTheDocument();

    // Verify page input exists
    expect(screen.getByLabelText(/current page/i)).toBeInTheDocument();
  });

  it("renders page size selector when enabled", () => {
    render(
      <NimbusProvider>
        <Pagination totalItems={100} enablePageSizeSelector={true} />
      </NimbusProvider>
    );

    // Verify page size selector is present
    expect(screen.getByLabelText(/items per page/i)).toBeInTheDocument();
    expect(screen.getByText(/items per page/i)).toBeInTheDocument();
  });

  it("hides page input when disabled", () => {
    render(
      <NimbusProvider>
        <Pagination totalItems={100} enablePageInput={false} />
      </NimbusProvider>
    );

    // Page input should not exist
    expect(screen.queryByLabelText(/current page/i)).not.toBeInTheDocument();

    // But current page number should still be displayed as text
    expect(screen.getByText("1")).toBeInTheDocument();
  });
});
```

